document.addEventListener("DOMContentLoaded",function(){const rawData=document.getElementById("datosEstadisticos").textContent.trim();try{const datos=JSON.parse(rawData);console.log("Datos cargados:",datos);if(!Array.isArray(datos)||datos.length===0){console.warn("No hay datos disponibles para graficar.");return;}const etiquetas=datos.map(item=>item.periodo);const visitas=datos.map(item=>parseInt(item.total_visitas,10));const contactos=datos.map(item=>parseInt(item.total_contactos,10));const tablaDatos=document.getElementById("tablaDatos");datos.forEach(item=>{tablaDatos.innerHTML+=`
                <tr>
                    <td>${item.periodo}</td>
                    <td>${item.total_visitas}</td>
                    <td>${item.total_contactos}</td>
                </tr>`;});const ctx=document.getElementById('graficoTrafico').getContext('2d');new Chart(ctx,{type:'line',data:{labels:etiquetas,datasets:[{label:'Visitas',data:visitas,backgroundColor:'rgba(54, 162, 235, 0.2)',borderColor:'rgba(54, 162, 235, 1)',borderWidth:2,fill:true},{label:'Contactos',data:contactos,backgroundColor:'rgba(255, 99, 132, 0.2)',borderColor:'rgba(255, 99, 132, 1)',borderWidth:2,fill:true}]},options:{responsive:true,scales:{y:{beginAtZero:true}}}});}catch(error){console.error("Error al procesar el JSON:",error);console.log("Datos recibidos:",rawData);}});